import React from 'react';
import { Card, CardContent, Box, Typography, LinearProgress, Stack } from '@mui/material';
import response from './response.json';

interface SavingsGoalData {
  goalName: string;
  targetAmount: number;
  currentAmount: number;
  percentageCompleted: number;
  projectedCompletionDate: string;
}

export default function Widget() {
  const { goalName, targetAmount, currentAmount, percentageCompleted, projectedCompletionDate } = response.data as SavingsGoalData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              {goalName}
            </Typography>
            <Stack direction="row" justifyContent="space-between">
              <Typography variant="body2" color="text.secondary">
                ${currentAmount.toLocaleString()} of ${targetAmount.toLocaleString()}
              </Typography>
              <Typography variant="body2" fontWeight={500} sx={{ color: '#4CAF50' }}>
                {percentageCompleted}%
              </Typography>
            </Stack>
          </Box>

          <LinearProgress
            variant="determinate"
            value={percentageCompleted}
            sx={{
              height: 8,
              borderRadius: 4,
              bgcolor: '#E0E0E0',
              '& .MuiLinearProgress-bar': {
                bgcolor: '#4CAF50',
                borderRadius: 4,
              }
            }}
          />

          <Typography variant="body2" color="text.secondary">
            Projected Completion: {new Date(projectedCompletionDate).toLocaleDateString()}
          </Typography>
        </Stack>
      </CardContent>
    </Card>
  );
}
